SELECT feedback.activity_id, feedback.user_id, feedback.rating
FROM feedback
WHERE feedback.rating = (
    SELECT MAX(rating)
    FROM feedback
);

SELECT AVG(engagement_score) as average_engagement_score
FROM user_engagements
WHERE user_id IN (
  SELECT user_id
  FROM feedback
)
AND user_id IN (
  SELECT user_id
  FROM user_events
);
